using Microsoft.ML.Data;

namespace TicketClassifier.Models;

/// <summary>
/// Input schema matching the training CSV.
/// </summary>
public class TicketInput
{
    [LoadColumn(0)]
    public string Subject { get; set; } = string.Empty;

    [LoadColumn(1)]
    public string Description { get; set; } = string.Empty;

    [LoadColumn(2)]
    public float Priority { get; set; }

    [LoadColumn(3)]
    [ColumnName("Category")]
    public string Category { get; set; } = string.Empty;
}

/// <summary>
/// ML.NET prediction output.
/// </summary>
public class TicketPrediction
{
    [ColumnName("PredictedLabel")]
    public string PredictedCategory { get; set; } = string.Empty;

    public float[] Score { get; set; } = [];
}

using System.ComponentModel.DataAnnotations;

namespace TicketClassifier.Models;

public class TicketRequest
{
    [Required]
    public string Subject { get; set; } = string.Empty;

    [Required]
    public string Description { get; set; } = string.Empty;

    [Range(1, 3)]
    public int Priority { get; set; }
}

namespace TicketClassifier.Models;

public class TicketResponse
{
    public string PredictedCategory { get; set; } = string.Empty;
    public Dictionary<string, float> Confidence { get; set; } = new();
}

using Microsoft.ML;
using TicketClassifier.Models;

namespace TicketClassifier.Services;

/// <summary>
/// Trains and evaluates the ticket classification model at startup,
/// then saves it to disk for PredictionEnginePool to load.
/// </summary>
public class ModelTrainerService : IHostedService
{
    private readonly ILogger<ModelTrainerService> _logger;
    private readonly string _dataPath;
    private readonly string _modelPath;

    public ModelTrainerService(ILogger<ModelTrainerService> logger, IWebHostEnvironment env)
    {
        _logger = logger;
        _dataPath = Path.Combine(env.ContentRootPath, "Data", "tickets.csv");
        _modelPath = Path.Combine(env.ContentRootPath, "Data", "model.zip");
    }

    public Task StartAsync(CancellationToken cancellationToken)
    {
        var mlContext = new MLContext(seed: 42);

        // Load data
        IDataView data = mlContext.Data.LoadFromTextFile<TicketInput>(
            _dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);

        // Train/test split — evaluate on held-out data, never on training data
        var split = mlContext.Data.TrainTestSplit(data, testFraction: 0.2, seed: 42);

        // Build pipeline: featurise text + priority → multiclass classifier
        var pipeline = mlContext.Transforms.Conversion
                .MapValueToKey("Label", nameof(TicketInput.Category))
            .Append(mlContext.Transforms.Text.FeaturizeText("SubjectFeatures", nameof(TicketInput.Subject)))
            .Append(mlContext.Transforms.Text.FeaturizeText("DescriptionFeatures", nameof(TicketInput.Description)))
            .Append(mlContext.Transforms.Concatenate("Features",
                "SubjectFeatures", "DescriptionFeatures", nameof(TicketInput.Priority)))
            .Append(mlContext.MulticlassClassification.Trainers.SdcaMaximumEntropy(
                labelColumnName: "Label", featureColumnName: "Features"))
            .Append(mlContext.Transforms.Conversion.MapKeyToValue("PredictedLabel"));

        // Train
        _logger.LogInformation("Training ticket classification model...");
        var model = pipeline.Fit(split.TrainSet);

        // Evaluate on test set
        var predictions = model.Transform(split.TestSet);
        var metrics = mlContext.MulticlassClassification.Evaluate(predictions, labelColumnName: "Label");

        _logger.LogInformation("=== Model Evaluation Metrics ===");
        _logger.LogInformation("  Macro Accuracy:    {MacroAccuracy:F4}", metrics.MacroAccuracy);
        _logger.LogInformation("  Micro Accuracy:    {MicroAccuracy:F4}", metrics.MicroAccuracy);
        _logger.LogInformation("  Log Loss:          {LogLoss:F4}", metrics.LogLoss);
        _logger.LogInformation("  Log Loss Reduction:{LogLossReduction:F4}", metrics.LogLossReduction);

        // Also log per-class metrics from the confusion matrix
        var confusionMatrix = metrics.ConfusionMatrix;
        _logger.LogInformation("  Per-class metrics:");
        for (int i = 0; i < confusionMatrix.PerClassPrecision.Count; i++)
        {
            _logger.LogInformation("    Class {Index}: Precision={Precision:F4}, Recall={Recall:F4}",
                i, confusionMatrix.PerClassPrecision[i], confusionMatrix.PerClassRecall[i]);
        }

        // Save model for PredictionEnginePool
        mlContext.Model.Save(model, data.Schema, _modelPath);
        _logger.LogInformation("Model saved to {Path}", _modelPath);

        return Task.CompletedTask;
    }

    public Task StopAsync(CancellationToken cancellationToken) => Task.CompletedTask;
}

using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.ML;
using TicketClassifier.Models;

namespace TicketClassifier.Controllers;

[ApiController]
[Route("api/[controller]")]
public class TicketsController : ControllerBase
{
    private readonly PredictionEnginePool<TicketInput, TicketPrediction> _predictionPool;

    public TicketsController(PredictionEnginePool<TicketInput, TicketPrediction> predictionPool)
    {
        _predictionPool = predictionPool;
    }

    [HttpPost("classify")]
    public ActionResult<TicketResponse> Classify([FromBody] TicketRequest request)
    {
        if (!ModelState.IsValid)
            return ValidationProblem();

        var input = new TicketInput
        {
            Subject = request.Subject,
            Description = request.Description,
            Priority = request.Priority,
        };

        var prediction = _predictionPool.Predict(input);

        // Map score array to category labels
        string[] labels = ["Billing", "General", "Technical"];
        var confidence = new Dictionary<string, float>();
        for (int i = 0; i < prediction.Score.Length && i < labels.Length; i++)
        {
            confidence[labels[i]] = prediction.Score[i];
        }

        return Ok(new TicketResponse
        {
            PredictedCategory = prediction.PredictedCategory,
            Confidence = confidence,
        });
    }
}

